function safeNum(x) {
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function pct(a, b) {
  if (!b) return null;
  return (a / b) * 100;
}

function fmtMoney(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return 'N/A';
  return `£${x.toLocaleString(undefined, { maximumFractionDigits: 0 })}`;
}

function fmtPct(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return 'N/A';
  return `${x.toFixed(2)}%`;
}

// QBR-aligned (POC) categorisation: CUG, Cashback, Discount, CSS, Subnetworks, Other
function inferPublisherType(nameRaw) {
  const name = String(nameRaw || '').toLowerCase();

  // Closed User Groups (CUG)
  if (/(blue light|defence|teachers|carers|charity worker|health service|totum|benifex|telus|perk|benefit|studentbeans|joinnetwork|perksatwork|nextjump)/.test(name))
    return 'Closed User Groups';

  // Cashback
  if (/(cashback|quidco|topcashback|easyfundraising|swagbucks|reward gateway|rakuten|give as you live|vc loyalty|wanteed)/.test(name))
    return 'Cashback';

  // Discount & Voucher Sites
  if (/(voucher|vouchers|codes|coupon|deal|deals|discount|hotukdeals|savoo|wowcher|bravovoucher|latest deals|vouchercloud|purpl|purplee|vcuk|atolls|mvc)/.test(name))
    return 'Discount & Voucher Sites';

  // CSS
  if (/(css|google shopping|comparison|compare|idealo|redbrain|shoparize|shopia|expandeo|priceplanet|delupe|top-css|zoliro)/.test(name))
    return 'CSS';

  // Subnetworks
  if (/(skimlinks|soreto|subnetwork|network|linkhaitao|affilizz|convert|digidip|takeads|linkbux|brandreward|ad pump|shoplooks)/.test(name))
    return 'Subnetworks';

  return 'Other';
}

const rows = $input.all().map(i => i.json);

const enriched = rows.map(d => {
  const impressions = safeNum(d.impressions);
  const clicks = safeNum(d.clicks);
  const sales = safeNum(d.sales);
  const orderValue = safeNum(d.orderValue);
  const pubComm = safeNum(d.publisherCommission);
  const tdComm = safeNum(d.tdCommission);

  return {
    sourceId: d.sourceId ?? '',
    sourceName: d.sourceName ?? 'Unknown',
    publisherType: inferPublisherType(d.sourceName),

    impressions,
    clicks,
    sales,
    orderValue,

    ctr: impressions ? pct(clicks, impressions) : null,
    cvr: clicks ? pct(sales, clicks) : null,
    epc: clicks ? (orderValue / clicks) : null,
    aov: sales ? (orderValue / sales) : null,
    takeRate: orderValue ? pct(pubComm + tdComm, orderValue) : null,

    pubComm,
    tdComm
  };
});

const byType = new Map();
for (const r of enriched) {
  if (!byType.has(r.publisherType)) byType.set(r.publisherType, []);
  byType.get(r.publisherType).push(r);
}

function topN(arr, n, key) {
  return [...arr].sort((a,b) => (b[key] ?? -Infinity) - (a[key] ?? -Infinity)).slice(0, n);
}

function buildWatchlist(pubs) {
  const sorted = [...pubs].sort((a,b) => b.clicks - a.clicks);
  const cutoff = sorted[Math.min(9, sorted.length - 1)]?.clicks ?? 0; // ~top-10 clicks cutoff

  return pubs
    .filter(p => p.clicks >= cutoff && p.clicks > 0)
    .sort((a,b) => (a.cvr ?? Infinity) - (b.cvr ?? Infinity))
    .slice(0, 8);
}

// Control output order to match QBR chapters
const orderedTypes = [
  'Closed User Groups',
  'Cashback',
  'Discount & Voucher Sites',
  'CSS',
  'Subnetworks',
  'Other'
];

const typeSummaries = [];
const sectionsForAI = [];

for (const type of orderedTypes) {
  const pubs = byType.get(type) || [];
  if (!pubs.length) continue;

  const totals = pubs.reduce((a,r) => {
    a.impressions += r.impressions;
    a.clicks += r.clicks;
    a.sales += r.sales;
    a.orderValue += r.orderValue;
    a.pubComm += r.pubComm;
    a.tdComm += r.tdComm;
    return a;
  }, { impressions:0, clicks:0, sales:0, orderValue:0, pubComm:0, tdComm:0 });

  const overall = {
    ctr: totals.impressions ? pct(totals.clicks, totals.impressions) : null,
    cvr: totals.clicks ? pct(totals.sales, totals.clicks) : null,
    epc: totals.clicks ? (totals.orderValue / totals.clicks) : null,
    aov: totals.sales ? (totals.orderValue / totals.sales) : null,
    takeRate: totals.orderValue ? pct(totals.pubComm + totals.tdComm, totals.orderValue) : null
  };

  const topByOV = topN(pubs, 12, 'orderValue');
  const watchlist = buildWatchlist(pubs);

  typeSummaries.push({ type, totals, overall, topByOV, watchlist });

  const lines = [];
  lines.push(`Performance by Publisher Type — ${type}`);
  lines.push(`Totals: OV ${fmtMoney(totals.orderValue)} | Sales ${totals.sales.toLocaleString()} | Clicks ${totals.clicks.toLocaleString()}`);
  lines.push(`Efficiency: EPC ${fmtMoney(overall.epc)} | CVR ${fmtPct(overall.cvr)} | AOV ${fmtMoney(overall.aov)} | Take ${fmtPct(overall.takeRate)}`);

  if (!totals.impressions) {
    lines.push('Data note: impressions missing/partial → CTR not reliable.');
  } else {
    lines.push(`CTR: ${fmtPct(overall.ctr)}`);
  }

  lines.push('');
  lines.push('Top publishers by Order Value:');
  topByOV.forEach((r, i) => {
    lines.push(`${i+1}. ${r.sourceName} (ID:${r.sourceId}) — OV ${fmtMoney(r.orderValue)} | Sales ${r.sales} | Clicks ${r.clicks} | EPC ${fmtMoney(r.epc)} | CVR ${fmtPct(r.cvr)}`);
  });

  if (watchlist.length) {
    lines.push('');
    lines.push('High-click / low-efficiency watchlist:');
    watchlist.forEach((r, i) => {
      lines.push(`${i+1}. ${r.sourceName} — Clicks ${r.clicks} | OV ${fmtMoney(r.orderValue)} | EPC ${fmtMoney(r.epc)} | CVR ${fmtPct(r.cvr)}`);
    });
  }

  sectionsForAI.push(lines.join('\n'));
}

return [{
  json: {
    disclaimer: 'Publisher types are inferred heuristically from publisher names for proof-of-concept only.',
    typeSummaries,
    dataForAI: sectionsForAI.join('\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n')
  }
}];
